#!/bin/bash
# Resolve (clear) a message via work-buddy's messaging service.
# This script is auto-generated by check_messages.sh on session start.
#
# Marks a message's status as 'resolved' (PATCH /messages/<id>) so it stops
# counting as pending — use it for a notification you've seen and need not act
# on, so it no longer keeps your Stop hook from letting the turn end.

SERVICE_URL="%%SERVICE_URL%%"

usage() {
    cat <<'HELP'
Usage: bash /tmp/wb/resolve [OPTIONS]

Mark a message resolved so it no longer blocks your turn from ending.
Use this for a notification you've read and don't need to act on.

Required:
  --id <message-id>      ID of the message to resolve (shown in message summaries)

Optional:
  --status <status>      Status to set (default: resolved)
  --help                 Show this help message

Examples:
  bash /tmp/wb/resolve --id 20260403T044932-work-buddy-c8ea288b
HELP
    exit 0
}

MSG_ID=""
STATUS="resolved"

while [ $# -gt 0 ]; do
    case "$1" in
        --id)       MSG_ID="$2"; shift 2 ;;
        --status)   STATUS="$2"; shift 2 ;;
        --help|-h)  usage ;;
        *)          echo "Unknown option: $1. Use --help for usage."; exit 1 ;;
    esac
done

if [ -z "$MSG_ID" ]; then echo "Error: --id is required. Use --help for usage."; exit 1; fi

python -c "
import json, sys, urllib.request, urllib.error

status = sys.argv[1]
url = sys.argv[2] + '/messages/' + sys.argv[3]
data = json.dumps({'status': status}).encode('utf-8')
req = urllib.request.Request(url, data=data, method='PATCH')
req.add_header('Content-Type', 'application/json')

try:
    with urllib.request.urlopen(req, timeout=5) as resp:
        result = json.loads(resp.read().decode('utf-8'))
        print('Resolved:', result['id'], '->', result['status'])
except urllib.error.HTTPError as e:
    if e.code == 404:
        print(f'Error: message not found: {sys.argv[3]}', file=sys.stderr)
    else:
        print(f'Error: HTTP {e.code}', file=sys.stderr)
    sys.exit(1)
except urllib.error.URLError:
    print('Error: Could not reach messaging service. Is it running?', file=sys.stderr)
    sys.exit(1)
" "$STATUS" "$SERVICE_URL" "$MSG_ID"
